-- Name: benchmark_symbols_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.benchmark_symbols_v AS
 SELECT secid,
    avg(value) AS avg_daily_value,
    (count(*))::integer AS daily_bars,
    (row_number() OVER (ORDER BY (avg(value)) DESC NULLS LAST, secid))::integer AS liquidity_rank
   FROM raw.candle
  WHERE ((engine = 'stock'::text) AND (interval_name = '1d'::text) AND ((candle_time)::date >= (CURRENT_DATE - '120 days'::interval)))
  GROUP BY secid
 HAVING (count(*) >= 10);


