--
-- Name: market_benchmark_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.market_benchmark_v AS
 WITH lookbacks(days) AS (
         VALUES (7), (30)
        ), symbols AS (
         SELECT benchmark_symbols_v.secid,
            benchmark_symbols_v.avg_daily_value
           FROM trading.benchmark_symbols_v
          WHERE (benchmark_symbols_v.liquidity_rank <= 10)
        ), priced AS (
         SELECT l.days,
            s.secid,
            s.avg_daily_value,
            ( SELECT (c.close)::numeric AS close
                   FROM raw.candle c
                  WHERE ((c.engine = 'stock'::text) AND (c.interval_name = '1d'::text) AND (c.secid = s.secid) AND ((c.candle_time)::date <= (CURRENT_DATE - l.days)))
                  ORDER BY c.candle_time DESC
                 LIMIT 1) AS start_close,
            ( SELECT (c.close)::numeric AS close
                   FROM raw.candle c
                  WHERE ((c.engine = 'stock'::text) AND (c.interval_name = '1d'::text) AND (c.secid = s.secid) AND ((c.candle_time)::date <= CURRENT_DATE))
                  ORDER BY c.candle_time DESC
                 LIMIT 1) AS end_close
           FROM (lookbacks l
             CROSS JOIN symbols s)
        ), symbol_returns AS (
         SELECT priced.days,
            priced.secid,
            priced.avg_daily_value,
                CASE
                    WHEN ((priced.start_close > (0)::numeric) AND (priced.end_close IS NOT NULL)) THEN (((priced.end_close / priced.start_close) - (1)::numeric) * (100)::numeric)
                    ELSE NULL::numeric
                END AS return_pct
           FROM priced
        )
 SELECT 'cash'::text AS benchmark_name,
    0 AS lookback_days,
    (0)::numeric AS return_pct,
    0 AS symbols_count,
    now() AS calculated_at
UNION ALL
 SELECT 'equal_weight_top_liquid'::text AS benchmark_name,
    symbol_returns.days AS lookback_days,
    avg(symbol_returns.return_pct) AS return_pct,
    (count(symbol_returns.return_pct))::integer AS symbols_count,
    now() AS calculated_at
   FROM symbol_returns
  GROUP BY symbol_returns.days
UNION ALL
 SELECT 'liquidity_weighted_buy_hold'::text AS benchmark_name,
    symbol_returns.days AS lookback_days,
    (sum((symbol_returns.return_pct * symbol_returns.avg_daily_value)) / NULLIF(sum(symbol_returns.avg_daily_value), (0)::numeric)) AS return_pct,
    (count(symbol_returns.return_pct))::integer AS symbols_count,
    now() AS calculated_at
   FROM symbol_returns
  GROUP BY symbol_returns.days;


ALTER VIEW trading.market_benchmark_v OWNER TO n8n_user;

