--
-- Name: trader_ai_failure_stats_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_ai_failure_stats_v AS
 SELECT COALESCE(trader_name, call_name) AS trader_name,
    (count(*))::integer AS ai_attempts,
    (count(*) FILTER (WHERE (status = 'success'::text)))::integer AS ai_successes,
    (count(*) FILTER (WHERE (status = ANY (ARRAY['exhausted'::text, 'timeout'::text, 'error'::text, 'parse_error'::text, 'budget_blocked'::text]))))::integer AS ai_failures,
    (count(*) FILTER (WHERE (status = 'budget_blocked'::text)))::integer AS ai_budget_blocks,
        CASE
            WHEN (count(*) > 0) THEN (((count(*) FILTER (WHERE (status = ANY (ARRAY['exhausted'::text, 'timeout'::text, 'error'::text, 'parse_error'::text, 'budget_blocked'::text]))))::numeric / (count(*))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS ai_failure_rate_pct,
    avg(prompt_chars) AS avg_prompt_chars,
    max(created_at) AS last_ai_call_at
   FROM trading.ai_call_log
  WHERE (category = 'trader'::text)
  GROUP BY COALESCE(trader_name, call_name);


ALTER VIEW trading.trader_ai_failure_stats_v OWNER TO n8n_user;

