--
-- Name: trader_position_value_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_position_value_v AS
 SELECT p.trader_name,
    p.secid,
    p.quantity,
    p.avg_entry_price,
    cp.price AS current_price,
    ((p.quantity)::numeric * COALESCE(cp.price, p.avg_entry_price)) AS position_value,
    ((p.quantity)::numeric * (COALESCE(cp.price, p.avg_entry_price) - p.avg_entry_price)) AS unrealized_pnl,
        CASE
            WHEN (p.avg_entry_price > (0)::numeric) THEN (((COALESCE(cp.price, p.avg_entry_price) / p.avg_entry_price) - (1)::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS unrealized_pnl_pct,
    cp.updated_at AS price_updated_at
   FROM (trading."position" p
     LEFT JOIN trading.current_prices_v cp ON (((cp.secid = p.secid) AND (cp.engine = 'stock'::text))))
  WHERE (p.quantity <> 0);


ALTER VIEW trading.trader_position_value_v OWNER TO n8n_user;

--
-- Name: trader_current_equity_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_current_equity_v AS
 SELECT pf.trader_name,
    (pf.cash_balance)::numeric AS cash_balance,
    COALESCE(sum(pv.position_value), (0)::numeric) AS positions_value,
    (pf.cash_balance + COALESCE(sum(pv.position_value), (0)::numeric)) AS total_equity,
    COALESCE(sum(abs(pv.position_value)), (0)::numeric) AS gross_exposure,
        CASE
            WHEN ((pf.cash_balance + COALESCE(sum(pv.position_value), (0)::numeric)) > (0)::numeric) THEN ((COALESCE(sum(abs(pv.position_value)), (0)::numeric) / (pf.cash_balance + COALESCE(sum(pv.position_value), (0)::numeric))) * (100)::numeric)
            ELSE (0)::numeric
        END AS gross_exposure_pct,
    (count(pv.secid))::integer AS open_positions,
    max(pv.price_updated_at) AS prices_updated_at,
    pf.updated_at AS portfolio_updated_at
   FROM (trading.portfolio pf
     LEFT JOIN trading.trader_position_value_v pv ON ((pv.trader_name = pf.trader_name)))
  GROUP BY pf.trader_name, pf.cash_balance, pf.updated_at;


ALTER VIEW trading.trader_current_equity_v OWNER TO n8n_user;

--
-- Name: trader_equity_daily_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_equity_daily_v AS
 SELECT daily_stats.trader_name,
    daily_stats.stat_date,
    (daily_stats.total_value)::numeric AS total_equity,
    (daily_stats.cash_balance)::numeric AS cash_balance,
    (daily_stats.positions_value)::numeric AS positions_value,
    daily_stats.created_at,
    'daily_stats'::text AS source
   FROM trading.daily_stats
UNION ALL
 SELECT c.trader_name,
    CURRENT_DATE AS stat_date,
    c.total_equity,
    c.cash_balance,
    c.positions_value,
    now() AS created_at,
    'current_equity'::text AS source
   FROM trading.trader_current_equity_v c
  WHERE (NOT (EXISTS ( SELECT 1
           FROM trading.daily_stats d
          WHERE ((d.trader_name = c.trader_name) AND (d.stat_date = CURRENT_DATE)))));


ALTER VIEW trading.trader_equity_daily_v OWNER TO n8n_user;

--
-- Name: trader_equity_curve_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_equity_curve_v AS
 SELECT trader_name,
    stat_date,
    total_equity,
    cash_balance,
    positions_value,
    source,
    lag(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date) AS previous_equity,
        CASE
            WHEN (lag(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date) > (0)::numeric) THEN (((total_equity / lag(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date)) - (1)::numeric) * (100)::numeric)
            ELSE NULL::numeric
        END AS daily_return_pct,
    max(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS peak_equity,
        CASE
            WHEN (max(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) > (0)::numeric) THEN (((total_equity / max(total_equity) OVER (PARTITION BY trader_name ORDER BY stat_date ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)) - (1)::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS drawdown_pct
   FROM trading.trader_equity_daily_v;


ALTER VIEW trading.trader_equity_curve_v OWNER TO n8n_user;

--
-- Name: trader_trade_outcomes_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_trade_outcomes_v AS
 SELECT j.id,
    j.trader_name,
    j.secid,
    upper(j.action) AS action,
    j.quantity,
    j.price,
    j.created_at,
    prior.avg_prior_buy_price,
        CASE
            WHEN (prior.avg_prior_buy_price > (0)::numeric) THEN ((j.price - prior.avg_prior_buy_price) * (j.quantity)::numeric)
            ELSE NULL::numeric
        END AS approx_realized_pnl,
        CASE
            WHEN (prior.avg_prior_buy_price > (0)::numeric) THEN (j.price > prior.avg_prior_buy_price)
            ELSE NULL::boolean
        END AS is_win
   FROM (trading.journal j
     LEFT JOIN LATERAL ( SELECT (sum(((b.quantity)::numeric * b.price)) / (NULLIF(sum(b.quantity), 0))::numeric) AS avg_prior_buy_price
           FROM trading.journal b
          WHERE ((b.trader_name = j.trader_name) AND (b.secid = j.secid) AND (upper(b.action) = ANY (ARRAY['BUY'::text, 'COVER'::text])) AND (b.created_at < j.created_at))) prior ON (true))
  WHERE (upper(j.action) = ANY (ARRAY['SELL'::text, 'SHORT'::text]));


ALTER VIEW trading.trader_trade_outcomes_v OWNER TO n8n_user;

--
-- Name: trader_trade_stats_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_trade_stats_v AS
 SELECT trader_name,
    (count(*))::integer AS trade_count,
    (count(*) FILTER (WHERE (upper(action) = 'BUY'::text)))::integer AS buy_count,
    (count(*) FILTER (WHERE (upper(action) = 'SELL'::text)))::integer AS sell_count,
    (count(*) FILTER (WHERE (upper(action) = 'SHORT'::text)))::integer AS short_count,
    (count(*) FILTER (WHERE (upper(action) = 'COVER'::text)))::integer AS cover_count,
    COALESCE(sum(abs(((quantity)::numeric * price))), (0)::numeric) AS turnover_value,
    min(created_at) AS first_trade_at,
    max(created_at) AS last_trade_at
   FROM trading.journal
  GROUP BY trader_name;


ALTER VIEW trading.trader_trade_stats_v OWNER TO n8n_user;

--
-- Name: trader_win_rate_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_win_rate_v AS
 SELECT trader_name,
    (count(*) FILTER (WHERE (is_win IS NOT NULL)))::integer AS evaluated_exits,
    (count(*) FILTER (WHERE (is_win IS TRUE)))::integer AS winning_exits,
    (count(*) FILTER (WHERE (is_win IS FALSE)))::integer AS losing_exits,
        CASE
            WHEN (count(*) FILTER (WHERE (is_win IS NOT NULL)) > 0) THEN (((count(*) FILTER (WHERE (is_win IS TRUE)))::numeric / (count(*) FILTER (WHERE (is_win IS NOT NULL)))::numeric) * (100)::numeric)
            ELSE NULL::numeric
        END AS win_rate_pct,
    COALESCE(sum(approx_realized_pnl), (0)::numeric) AS approx_realized_pnl
   FROM trading.trader_trade_outcomes_v
  GROUP BY trader_name;


ALTER VIEW trading.trader_win_rate_v OWNER TO n8n_user;

--
-- Name: trader_performance_v; Type: VIEW; Schema: trading; Owner: n8n_user
--

CREATE VIEW trading.trader_performance_v AS
 WITH curve AS (
         SELECT trader_equity_curve_v.trader_name,
            min(trader_equity_curve_v.drawdown_pct) AS max_drawdown_pct,
            (count(*))::integer AS equity_points
           FROM trading.trader_equity_curve_v
          GROUP BY trader_equity_curve_v.trader_name
        ), initial_capital AS (
         SELECT p.trader_name,
            COALESCE(( SELECT (d.total_value)::numeric AS total_value
                   FROM trading.daily_stats d
                  WHERE (d.trader_name = p.trader_name)
                  ORDER BY d.stat_date
                 LIMIT 1), (10000)::numeric) AS initial_capital
           FROM trading.portfolio p
        )
 SELECT e.trader_name,
    ic.initial_capital,
    e.cash_balance,
    e.positions_value,
    e.total_equity,
    e.gross_exposure,
    e.gross_exposure_pct,
    e.open_positions,
        CASE
            WHEN (ic.initial_capital > (0)::numeric) THEN (((e.total_equity / ic.initial_capital) - (1)::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS return_pct,
    COALESCE(c.max_drawdown_pct, (0)::numeric) AS max_drawdown_pct,
    COALESCE(w.win_rate_pct, NULL::numeric) AS win_rate_pct,
    COALESCE(w.evaluated_exits, 0) AS evaluated_exits,
    COALESCE(w.approx_realized_pnl, (0)::numeric) AS approx_realized_pnl,
    COALESCE(t.trade_count, 0) AS trade_count,
    COALESCE(t.turnover_value, (0)::numeric) AS turnover_value,
        CASE
            WHEN (e.total_equity > (0)::numeric) THEN (COALESCE(t.turnover_value, (0)::numeric) / e.total_equity)
            ELSE (0)::numeric
        END AS turnover_to_equity,
    COALESCE(ai.ai_attempts, 0) AS ai_attempts,
    COALESCE(ai.ai_failures, 0) AS ai_failures,
    COALESCE(ai.ai_failure_rate_pct, (0)::numeric) AS ai_failure_rate_pct,
    (((
        CASE
            WHEN (ic.initial_capital > (0)::numeric) THEN (((e.total_equity / ic.initial_capital) - (1)::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END + (COALESCE(c.max_drawdown_pct, (0)::numeric) * 0.70)) - (LEAST((COALESCE(t.turnover_value, (0)::numeric) / NULLIF(e.total_equity, (0)::numeric)), (20)::numeric) * 0.10)) - (COALESCE(ai.ai_failure_rate_pct, (0)::numeric) * 0.05)) AS tuning_score,
    e.prices_updated_at,
    t.first_trade_at,
    t.last_trade_at,
    ai.last_ai_call_at
   FROM (((((trading.trader_current_equity_v e
     JOIN initial_capital ic ON ((ic.trader_name = e.trader_name)))
     LEFT JOIN curve c ON ((c.trader_name = e.trader_name)))
     LEFT JOIN trading.trader_trade_stats_v t ON ((t.trader_name = e.trader_name)))
     LEFT JOIN trading.trader_win_rate_v w ON ((w.trader_name = e.trader_name)))
     LEFT JOIN trading.trader_ai_failure_stats_v ai ON ((ai.trader_name = e.trader_name)));


ALTER VIEW trading.trader_performance_v OWNER TO n8n_user;

